import { Injectable } from '@angular/core';
import { filter, take } from 'rxjs';
import { BaseService } from '../Base/base.service';
import { Ingredient } from '../../models';


@Injectable({
  providedIn: 'root'
})
export class IngredientService extends BaseService<Ingredient> {

  constructor() {
    super();
    this.authService.currentUser$
      .pipe(filter(u => !!u), take(1))
      .subscribe(() => {
        this.loadData();
      });
  }

  // ✅ IMPLEMENTA IL METODO ASTRATTO RICHIESTO
  override getTableName(): string {
    return 'ingredients';
  }

  // ✅ OVERRIDE PER INCLUDERE LE RELAZIONI
  override async loadData(additionalFilters?: any): Promise<void> {
    try {
      this.loadingSubject.next(true);
      const restaurantId = await this.getCurrentRestaurantId();
      
      if (!restaurantId) {
        this.dataSubject.next([]);
        this.loadingSubject.next(false);
        return;
      }

      const { data: ingredients, error } = await this.supabaseService.getSupabaseClient()
        .from('ingredients')
        .select(`
          *,
          units (*),
          suppliers (company_name, contact_name),
          ingredient_types (id, name, description),
          ingredient_groups (id, name, description, color)
        `)
        .eq('restaurant_id', restaurantId)
        .eq('is_active', true)
        .order('name');

      if (error) throw error;

      console.log('Ingredients loaded with details:', ingredients?.length);
      
      const processedIngredients = (ingredients || []).map(ingredient => ({
        ...ingredient,
        to_buy: ingredient.to_buy || false,
        to_buy_quantity: ingredient.to_buy_quantity || null,
        // Normalizza le relazioni
        ingredient_types: ingredient.ingredient_types || undefined,
        ingredient_groups: ingredient.ingredient_groups || undefined
      }));
      
      this.dataSubject.next(processedIngredients);
      
    } catch (error) {
      console.error('Error loading ingredients:', error);
      this.handleError('loadData', error);
    } finally {
      this.loadingSubject.next(false);
    }
  }



  // ✅ ALIAS PER COMPATIBILITÀ - USA loadData() INTERNAMENTE
  async loadIngredients(): Promise<void> {
    return this.loadData();
  }

  async createIngredient(ingredient: Omit<Ingredient, 'id' | 'created_at' | 'restaurant_id'>): Promise<Ingredient | null> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) {
        console.error('No restaurant found');
        return null;
      }

      // PULIZIA DEI DATI
      const cleanedIngredient = {
        ...ingredient,
        to_buy: ingredient.to_buy || false,
        to_buy_quantity: ingredient.to_buy_quantity || null,
        expiry_date: ingredient.expiry_date === '' ? null : ingredient.expiry_date,
        supplier_id: ingredient.supplier_id === '' ? null : ingredient.supplier_id,
        type_id: ingredient.type_id === '' ? null : ingredient.type_id,
        group_id: ingredient.group_id === '' ? null : ingredient.group_id,
        restaurant_id: restaurantId
      };

      console.log('📝 Creating ingredient:', cleanedIngredient);

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .insert(cleanedIngredient)
        .select(`
          *,
          units (*),
          suppliers (company_name, contact_name),
          ingredient_types (id, name, description),
          ingredient_groups (id, name, description, color)
        `)
        .single();

      if (error) {
        console.error('❌ Error creating ingredient:', error);
        throw error;
      }
      
      console.log('✅ Ingredient created successfully');
      await this.loadData();
      return data;
    } catch (error) {
      console.error('💥 Error in createIngredient:', error);
      return null;
    }
  }


  // ✅ METODI AGGIORNATI PER USARE loadData()
  async updateIngredient(id: string, updates: Partial<Ingredient>): Promise<boolean> {
    try {
      const cleanedUpdates = {
        ...updates,
        expiry_date: updates.expiry_date === '' ? null : updates.expiry_date,
        type_id: updates.type_id === '' ? null : updates.type_id,
        group_id: updates.group_id === '' ? null : updates.group_id
      };

      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .update(cleanedUpdates)
        .eq('id', id);

      if (error) throw error;
      
      await this.loadData();
      return true;
    } catch (error) {
      console.error('Error updating ingredient:', error);
      return false;
    }
  }

  async deleteIngredient(id: string): Promise<boolean> {
    try {
      const { error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .update({ is_active: false })
        .eq('id', id);

      if (error) throw error;
      
      await this.loadData(); // ✅ USA loadData()
      return true;
    } catch (error) {
      console.error('Error deleting ingredient:', error);
      return false;
    }
  }

  // ✅ METODI DI UTILITY - USANO dataSubject DI BaseService
  getIngredients(): Ingredient[] {
    return this.dataSubject.value;
  }

  getIngredientById(id: string): Ingredient | undefined {
    return this.dataSubject.value.find(ing => ing.id === id);
  }

  getLowStockIngredients(): Ingredient[] {
    return this.dataSubject.value.filter(ingredient => 
      ingredient.alert_enabled && ingredient.current_stock <= ingredient.minimum_stock
    );
  }

  searchIngredients(searchTerm: string): Ingredient[] {
    if (!searchTerm) return this.dataSubject.value;
    
    return this.dataSubject.value.filter(ingredient =>
      ingredient.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      ingredient.description?.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }

  calculateIngredientCost(ingredient: Ingredient, quantity: number): number {
    if (!ingredient.unit_id || !ingredient.units) {
      return ingredient.cost_per_unit * quantity;
    }

    const unit = ingredient.units;
    let convertedQuantity = quantity;

    // Converti la quantità in base all'unità di misura
    switch (unit.symbol) {
      case 'kg':
        convertedQuantity = quantity / 1000;
        break;
      case 'L':
        convertedQuantity = quantity / 1000;
        break;
      case 'g':
      case 'mL':
      case 'pz':
        convertedQuantity = quantity;
        break;
      default:
        convertedQuantity = quantity;
    }

    return ingredient.cost_per_unit * convertedQuantity;
  }

    // ✅ NUOVI METODI PER FILTRARE
  getIngredientsByType(typeId: string): Ingredient[] {
    return this.dataSubject.value.filter(ing => ing.type_id === typeId);
  }

  getIngredientsByGroup(groupId: string): Ingredient[] {
    return this.dataSubject.value.filter(ing => ing.group_id === groupId);
  }

  getIngredientsGroupedByType(): Map<string, Ingredient[]> {
    const grouped = new Map<string, Ingredient[]>();
    
    this.dataSubject.value.forEach(ingredient => {
      const typeId = ingredient.type_id || 'senza-tipologia';
      if (!grouped.has(typeId)) {
        grouped.set(typeId, []);
      }
      grouped.get(typeId)!.push(ingredient);
    });
    
    return grouped;
  }

  getIngredientsGroupedByGroup(): Map<string, Ingredient[]> {
    const grouped = new Map<string, Ingredient[]>();
    
    this.dataSubject.value.forEach(ingredient => {
      const groupId = ingredient.group_id || 'senza-gruppo';
      if (!grouped.has(groupId)) {
        grouped.set(groupId, []);
      }
      grouped.get(groupId)!.push(ingredient);
    });
    
    return grouped;
  }

}